/**
 * One row from `vendor_merge_audit_log` as returned by the list
endpoint. Mirrors the storage shape but omits the heavy
`counts` map and `loserSnapshot` jsonb columns — those are
only fetched on demand from the detail endpoint to keep the
list response small even after years of merges accumulate.

 */
export interface VendorMergeAuditLogSummary {
  id: number;
  /**
   * FK to `vendors.id`. NULL only if the survivor vendor was
itself later deleted (the FK is `ON DELETE SET NULL`).

   * @nullable
   */
  survivorVendorId?: number | null;
  survivorVendorName: string;
  /** Plain integer (no FK) — the loser row was deleted in the
same transaction as the merge.
 */
  loserVendorId: number;
  loserVendorName: string;
  totalMoved: number;
  totalConflictDeleted: number;
  /** @nullable */
  actorUserId?: number | null;
  /**
   * Display name of the admin who initiated the merge,
joined from `users.display_name` at read time. NULL if
the user was deleted (FK is `ON DELETE SET NULL`).

   * @nullable
   */
  actorDisplayName?: string | null;
  actorRole: string;
  createdAt: string;
  /**
   * When this merge was undone via the admin "Undo merge"
action, or null if it has never been reverted. Used by the
history page to render a "Reverted" badge and disable the
Undo affordance.

   * @nullable
   */
  revertedAt?: string | null;
  /**
   * Display name of the admin who clicked Undo, joined from
`users.display_name`. NULL if the merge has not been
reverted, or if the reverting admin has since been deleted.

   * @nullable
   */
  revertedByDisplayName?: string | null;
}

export interface ListVendorMergeAuditLogResponse {
  items: VendorMergeAuditLogSummary[];
  /** Total number of rows in `vendor_merge_audit_log`
(independent of the current `limit` / `offset`). The
admin UI uses this to render "showing N of M" and to
decide whether a "Load more" affordance is needed.
 */
  total: number;
  /** The effective limit applied to this response. */
  limit: number;
  /** The offset applied to this response. */
  offset: number;
}

/**
 * Verbatim copy of the loser `vendors` row at merge time
(name, contact info, addresses, tax IDs, logoUrl, etc.).
Stored as jsonb so older rows keep their shape across
schema migrations.

 */
export type VendorMergeAuditLogDetailLoserSnapshot = { [key: string]: unknown };

/**
 * Per-table counts. Keys are SQL table names (e.g.
`tickets`, `invoices`); each value is the
`{ move, conflictDelete }` pair the merge produced for
that table.

 */
export type VendorMergeAuditLogDetailCounts = {
  [key: string]: VendorMergeCount;
};

/**
 * The vendor currently occupying the loser's original id, or
null when the id is free. The admin UI uses this to explain
why "Revert this merge" is disabled.

 * @nullable
 */
export type VendorMergeAuditLogDetailConflictingVendor = {
  id: number;
  name: string;
} | null;

/**
 * Full audit row for a single past merge — same as the summary
plus the heavy `counts` and `loserSnapshot` jsonb columns and
the captured request-context fields (IP / user agent).

 */
export interface VendorMergeAuditLogDetail {
  id: number;
  /** @nullable */
  survivorVendorId?: number | null;
  survivorVendorName: string;
  loserVendorId: number;
  loserVendorName: string;
  /** Verbatim copy of the loser `vendors` row at merge time
(name, contact info, addresses, tax IDs, logoUrl, etc.).
Stored as jsonb so older rows keep their shape across
schema migrations.
 */
  loserSnapshot: VendorMergeAuditLogDetailLoserSnapshot;
  /** Per-table counts. Keys are SQL table names (e.g.
`tickets`, `invoices`); each value is the
`{ move, conflictDelete }` pair the merge produced for
that table.
 */
  counts: VendorMergeAuditLogDetailCounts;
  totalMoved: number;
  totalConflictDeleted: number;
  /** @nullable */
  actorUserId?: number | null;
  /** @nullable */
  actorDisplayName?: string | null;
  actorRole: string;
  /** @nullable */
  actorIp?: string | null;
  /** @nullable */
  actorUserAgent?: string | null;
  createdAt: string;
  /** True when the original loser vendor id is currently free
and the merge can be reverted. False when another vendor
row has since taken that numeric id (in which case
`conflictingVendor` describes who).
 */
  loserIdAvailable: boolean;
  /**
   * The vendor currently occupying the loser's original id, or
null when the id is free. The admin UI uses this to explain
why "Revert this merge" is disabled.

   * @nullable
   */
  conflictingVendor: VendorMergeAuditLogDetailConflictingVendor;
  /**
   * When this merge was undone via the admin "Undo merge"
action, or null if it has never been reverted.

   * @nullable
   */
  revertedAt?: string | null;
  /** @nullable */
  revertedByUserId?: number | null;
  /**
   * Display name of the admin who clicked Undo, joined from
`users.display_name`. NULL if the merge has not been
reverted, or if the reverting admin has since been deleted.

   * @nullable
   */
  revertedByDisplayName?: string | null;
}

