export type OrgMemberRowRole =
  (typeof OrgMemberRowRole)[keyof typeof OrgMemberRowRole];

export const OrgMemberRowRole = {
  admin: "admin",
  member: "member",
  ap: "ap",
  field_employee: "field_employee",
} as const;

/**
 * Single row in the listing returned by
`GET /orgs/{orgType}/{orgId}/members`. `role` includes
`field_employee` because the listing surfaces field-employee
memberships read-only — they exist on the org but are
managed via the field-employee tools (the add / remove /
patch endpoints reject `field_employee` rows). `legacyRole`
is the `users.role` column kept for back-compat with older
session-derived role checks (e.g. `admin`, `partner`,
`vendor`, `field_employee`); the canonical per-org role is
`role`.

For vendor orgs the row is LEFT JOIN'd against
`vendor_people` on `user_id` (and `vendor_id = orgId`) so
admins / members who also happen to be a field-employee
record on the same vendor surface their `phone` and
`pec_expiration_date` here. Both fields are nullable and
always null for partner-org members (partners have no
field-employee records).

 */
export interface OrgMemberRow {
  membershipId: number;
  userId: number;
  username: string;
  displayName: string;
  role: OrgMemberRowRole;
  legacyRole: string;
  /** Free-text job title from the matching `vendor_people`
row, or null when the member has no field-employee
record on this vendor (or the org is a partner).
 */
  jobTitle?: string | null;
  /** Profile photo URL from the matching `vendor_people`
row, or null when the member has no field-employee
record on this vendor (or the org is a partner).
 */
  photoUrl?: string | null;
  /** E.164-ish phone string from the matching `vendor_people`
row, or null when the member has no field-employee
record on this vendor (or the org is a partner).
 */
  phone?: string | null;
  /** ISO date (YYYY-MM-DD) of the matching `vendor_people`
PEC expiration, or null when the member has no field-
employee record on this vendor (or the org is a partner,
or the field-employee row has no PEC certification).
 */
  pecExpirationDate?: string | null;
}

